7. public class TicketClassifierService
8. {
9.     private readonly string _dataPath;
10.     private readonly MLContext _mlContext;
11.     private readonly object _lock = new();
12.     private PredictionEngine<TicketData, TicketPrediction>? _predictionEngine;
13.     private ITransformer? _model;
14.     private string[] _categoryNames = [];
15. 
16.     public bool IsModelTrained => _model is not null;
17. 
18.     public TicketClassifierService(IWebHostEnvironment env)
19.     {
20.         _dataPath = Path.Combine(env.ContentRootPath, "Data", "tickets.csv");
21.         _mlContext = new MLContext(seed: 42);
22.     }
23. 
24.     public TrainResponse TrainModel()
25.     {
26.         var data = _mlContext.Data.LoadFromTextFile<TicketData>(
27.             _dataPath, hasHeader: true, separatorChar: ',', allowQuoting: true);
28. 
29.         var pipeline = _mlContext.Transforms.Conversion.MapValueToKey("Label")
30.             .Append(_mlContext.Transforms.Text.FeaturizeText("SubjectFeaturized", "Subject"))
31.             .Append(_mlContext.Transforms.Text.FeaturizeText("DescriptionFeaturized", "Description"))
32.             .Append(_mlContext.Transforms.Concatenate("Features", "SubjectFeaturized", "DescriptionFeaturized", "Priority"))
33.             .Append(_mlContext.Transforms.NormalizeMinMax("Features"))
34.             .Append(_mlContext.MulticlassClassification.Trainers.SdcaMaximumEntropy("Label", "Features"))
35.             .Append(_mlContext.Transforms.Conversion.MapKeyToValue("PredictedLabel"));
36. 
37.         // Cross-validate with 3 folds on this small dataset
38.         var cvResults = _mlContext.MulticlassClassification.CrossValidate(
39.             data, pipeline, numberOfFolds: 3);
40. 
41.         double microAccuracy = cvResults.Average(r => r.Metrics.MicroAccuracy);
42.         double macroAccuracy = cvResults.Average(r => r.Metrics.MacroAccuracy);
43.         double logLoss = cvResults.Average(r => r.Metrics.LogLoss);
44.         double logLossReduction = cvResults.Average(r => r.Metrics.LogLossReduction);
45. 
46.         // Train final model on full dataset
47.         var model = pipeline.Fit(data);
48. 
49.         // Extract category slot names from the Score column
50.         var schema = model.GetOutputSchema(data.Schema);
51.         var scoreColumn = schema["Score"];
52.         var slotNames = new VBuffer<ReadOnlyMemory<char>>();
53.         scoreColumn.GetSlotNames(ref slotNames);
54.         var categoryNames = slotNames.DenseValues()
55.             .Select(v => v.ToString())
56.             .ToArray();
57. 
58.         lock (_lock)
59.         {
60.             _model = model;
61.             _categoryNames = categoryNames;
62.             _predictionEngine = _mlContext.Model.CreatePredictionEngine<TicketData, TicketPrediction>(model);
63.         }
64. 
65.         return new TrainResponse
66.         {
67.             MicroAccuracy = microAccuracy,
68.             MacroAccuracy = macroAccuracy,
69.             LogLoss = logLoss,
70.             LogLossReduction = logLossReduction,
71.             Message = "Model trained successfully. Note: metrics are from 3-fold cross-validation " +
72.                       "on only 6 samples, so they may not be fully representative."
73.         };
74.     }
75. 
76.     public PredictResponse Predict(PredictRequest request)
77.     {
78.         lock (_lock)
79.         {
80.             if (_predictionEngine is null)
81.                 throw new InvalidOperationException("Model has not been trained. Call the train endpoint first.");
82. 
83.             var ticketData = new TicketData
84.             {
85.                 Subject = request.Subject,
86.                 Description = request.Description,
87.                 Priority = (float)request.Priority
88.             };
89. 
90.             var prediction = _predictionEngine.Predict(ticketData);
91. 
92.             var categoryScores = new Dictionary<string, double>();
93.             for (int i = 0; i < _categoryNames.Length && i < prediction.Score.Length; i++)
94.             {
95.                 categoryScores[_categoryNames[i]] = Math.Round(prediction.Score[i], 4);
96.             }
97. 
98.             double confidence = prediction.Score.Length > 0 ? Math.Round(prediction.Score.Max(), 4) : 0;
99. 
100.             return new PredictResponse
