 using Microsoft.ML;
 using Microsoft.ML.Data;
 using TicketClassifier.Models;

 namespace TicketClassifier.Services;

 public class TicketClassifierService
 {
     private readonly string _dataPath;
     private readonly MLContext _mlContext;
     private readonly object _lock = new();
     private PredictionEngine<TicketData, TicketPrediction>? _predictionEngine;
     private ITransformer? _model;
     private string[] _categoryNames = [];

     public bool IsModelTrained => _model is not null;

     public TicketClassifierService(IWebHostEnvironment env)
     {
         _dataPath = Path.Combine(env.ContentRootPath, "Data", "tickets.csv");
         _mlContext = new MLContext(seed: 42);
     }

     public TrainResponse TrainModel()
     {
         var data = _mlContext.Data.LoadFromTextFile<TicketData>(
             _dataPath, hasHeader: true, separatorChar: ',', allowQuoting: true);

         var pipeline = _mlContext.Transforms.Conversion.MapValueToKey("Label")
             .Append(_mlContext.Transforms.Text.FeaturizeText("SubjectFeaturized", "Subject"))
             .Append(_mlContext.Transforms.Text.FeaturizeText("DescriptionFeaturized", "Description"))
             .Append(_mlContext.Transforms.Concatenate("Features", "SubjectFeaturized", "DescriptionFeaturized", "Priority"))
             .Append(_mlContext.Transforms.NormalizeMinMax("Features"))
             .Append(_mlContext.MulticlassClassification.Trainers.SdcaMaximumEntropy("Label", "Features"))
             .Append(_mlContext.Transforms.Conversion.MapKeyToValue("PredictedLabel"));

         // Cross-validate with 3 folds on this small dataset
         var cvResults = _mlContext.MulticlassClassification.CrossValidate(
             data, pipeline, numberOfFolds: 3);

         double microAccuracy = cvResults.Average(r => r.Metrics.MicroAccuracy);
         double macroAccuracy = cvResults.Average(r => r.Metrics.MacroAccuracy);
         double logLoss = cvResults.Average(r => r.Metrics.LogLoss);
         double logLossReduction = cvResults.Average(r => r.Metrics.LogLossReduction);

         // Train final model on full dataset
         var model = pipeline.Fit(data);

         // Extract category slot names from the Score column
         var schema = model.GetOutputSchema(data.Schema);
         var scoreColumn = schema["Score"];
         var slotNames = new VBuffer<ReadOnlyMemory<char>>();
         scoreColumn.GetSlotNames(ref slotNames);
         var categoryNames = slotNames.DenseValues()
             .Select(v => v.ToString())
             .ToArray();

         lock (_lock)
         {
             _model = model;
             _categoryNames = categoryNames;
             _predictionEngine = _mlContext.Model.CreatePredictionEngine<TicketData, TicketPrediction>(model);
         }

         return new TrainResponse
         {
             MicroAccuracy = microAccuracy,
             MacroAccuracy = macroAccuracy,
             LogLoss = logLoss,
             LogLossReduction = logLossReduction,
             Message = "Model trained successfully. Note: metrics are from 3-fold cross-validation " +
                       "on only 6 samples, so they may not be fully representative."
         };
     }

     public PredictResponse Predict(PredictRequest request)
     {
         lock (_lock)
         {
             if (_predictionEngine is null)
                 throw new InvalidOperationException("Model has not been trained. Call the train endpoint first.");

             var ticketData = new TicketData
             {
                 Subject = request.Subject,
                 Description = request.Description,
                 Priority = (float)request.Priority
             };

             var prediction = _predictionEngine.Predict(ticketData);

             var categoryScores = new Dictionary<string, double>();
             for (int i = 0; i < _categoryNames.Length && i < prediction.Score.Length; i++)
             {
                 categoryScores[_categoryNames[i]] = Math.Round(prediction.Score[i], 4);
             }

             double confidence = prediction.Score.Length > 0 ? Math.Round(prediction.Score.Max(), 4) : 0;

             return new PredictResponse
             {
                 Category = prediction.PredictedLabel,
                 Confidence = confidence,
                 CategoryScores = categoryScores
             };
         }
     }
 }

