             if (_predictionEngine is null)
                 throw new InvalidOperationException("Model has not been trained. Call the train endpoint first.");

             var ticketData = new TicketData
             {
                 Subject = request.Subject,
                 Description = request.Description,
                 Priority = (float)request.Priority
             };

             var prediction = _predictionEngine.Predict(ticketData);

             var categoryScores = new Dictionary<string, double>();
             for (int i = 0; i < _categoryNames.Length && i < prediction.Score.Length; i++)
             {
                 categoryScores[_categoryNames[i]] = Math.Round(prediction.Score[i], 4);
             }

             double confidence = prediction.Score.Length > 0 ? Math.Round(prediction.Score.Max(), 4) : 0;

             return new PredictResponse
             {
                 Category = prediction.PredictedLabel,
                 Confidence = confidence,
                 CategoryScores = categoryScores
             };
         }
     }
 }

